// Extract campaign config from webhook
const campaign = $input.first().json.body;
return [{
  json: {
    campaignId: campaign.campaignId,
    serviceDescription: campaign.serviceDescription || 'AI-powered lead generation',
    tone: campaign.tone || 'friendly',
    specialOffer: campaign.specialOffer || '',
    channels: campaign.channels || ['email', 'whatsapp']
  }
}];

// Merge campaign config with each lead
const campaign = $('Extract Campaign Config').first().json;
const leads = $input.all();

return leads.map(lead => ({
  json: {
    ...lead.json,
    campaignId: campaign.campaignId,
    serviceDescription: campaign.serviceDescription,
    tone: campaign.tone,
    specialOffer: campaign.specialOffer,
    channels: campaign.channels
  }
}));

