// Parse AI response and save each message to the DB
const lead = $('Merge Lead + Campaign').first().json;
const aiResponse = JSON.parse($input.first().json.message.content);

const messages = [];

// Initial messages per channel
if (lead.channels.includes('whatsapp') && aiResponse.message_whatsapp) {
  messages.push({
    lead_id: lead.id,
    campaign_id: lead.campaignId,
    channel: 'whatsapp',
    content: aiResponse.message_whatsapp,
    type: 'initial',
    status: 'pending'
  });
}

if (lead.channels.includes('email') && aiResponse.message_email_body) {
  messages.push({
    lead_id: lead.id,
    campaign_id: lead.campaignId,
    channel: 'email',
    content: JSON.stringify({ subject: aiResponse.message_email_subject, body: aiResponse.message_email_body }),
    type: 'initial',
    status: 'pending'
  });
}

if (lead.channels.includes('linkedin') && aiResponse.message_linkedin) {
  messages.push({
    lead_id: lead.id,
    campaign_id: lead.campaignId,
    channel: 'linkedin',
    content: aiResponse.message_linkedin,
    type: 'initial',
    status: 'pending'
  });
}

// Follow-ups (stored with scheduled_at offsets)
const followups = [
  { type: 'followup1', content: aiResponse.followup_day3, dayOffset: 3 },
  { type: 'followup2', content: aiResponse.followup_day6, dayOffset: 6 },
  { type: 'followup3', content: aiResponse.followup_day10, dayOffset: 10 }
];

for (const fu of followups) {
  if (fu.content) {
    const scheduledAt = new Date();
    scheduledAt.setDate(scheduledAt.getDate() + fu.dayOffset);
    messages.push({
      lead_id: lead.id,
      campaign_id: lead.campaignId,
      channel: lead.channels[0],
      content: fu.content,
      type: fu.type,
      status: 'scheduled',
      scheduled_at: scheduledAt.toISOString()
    });
  }
}

return messages.map(m => ({ json: m }));
